// region must-as-model-type functions

std::logic_error ErrorForUnexpectedModelType(
  types::ModelType expected,
  types::ModelType got
) {
  std::ostringstream ss;
  ss 
    << "Expected model type " << stringification.to_string(expected)
    << ", but got " << stringification.to_string(got);
  return std::logic_error(ss.str());
}

// region MustAsHasSemantics

std::shared_ptr<
  types::IHasSemantics
> MustAsHasSemantics(
  std::shared_ptr<types::IClass> that
) {
  if (!IsHasSemantics(that)) {
    throw ErrorForUnexpectedModelType(
      types::ModelType::kHasSemantics,
      that->model_type()
    );
  }
  return std::static_pointer_cast<
    types::IHasSemantics
  >(that);
}

